import React, { useState, useEffect } from 'react';
import { TrendingDown, TrendingUp, Wallet, History, CalendarDays } from 'lucide-react';
import { supabaseClient } from '../services/supabase';
import { Month } from '../types';

interface OverviewProps {
  currentMonth: Month;
  refresh: () => void;
}

const Overview: React.FC<OverviewProps> = ({ currentMonth, refresh }) => {
  const [totals, setTotals] = useState({ revenue: 0, expenses: 0, balance: 0 });
  const [recentTransactions, setRecentTransactions] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchData();
  }, [currentMonth]);

  const fetchData = async () => {
    setLoading(true);
    try {
      const [receitasRes, despesasRes, pixRes, bancosRes] = await Promise.all([
        supabaseClient.from('receitas').select('valor, descricao, data, criado_em').eq('mes_id', currentMonth.id),
        supabaseClient.from('despesas_contas').select('valor, descricao, data, criado_em, pago').eq('mes_id', currentMonth.id),
        supabaseClient.from('despesas_pix_credito').select('valor_final, descricao, data, criado_em, pago').eq('mes_id', currentMonth.id),
        supabaseClient.from('banco_despesas').select('valor, descricao, data, criado_em, pago').eq('mes_id', currentMonth.id)
      ]);

      const rev = receitasRes.data?.reduce((acc, curr) => acc + curr.valor, 0) || 0;

      // LOGICA ALTERADA: Contabilizar TODAS as despesas (pagas ou não)
      // O usuário solicitou que despesas em aberto já afetem o saldo real.
      const expContas = despesasRes.data?.reduce((acc, curr) => acc + curr.valor, 0) || 0;
      const expPix = pixRes.data?.reduce((acc, curr) => acc + curr.valor_final, 0) || 0;
      const expBancos = bancosRes.data?.reduce((acc, curr) => acc + curr.valor, 0) || 0;

      const totalExp = expContas + expPix + expBancos;

      setTotals({
        revenue: rev,
        expenses: totalExp,
        balance: rev - totalExp
      });

      const allItems = [
        ...(receitasRes.data || []).map(i => ({ ...i, type: 'revenue' })),
        ...(despesasRes.data || []).map(i => ({ ...i, type: 'expense' })),
        ...(pixRes.data || []).map(i => ({ ...i, type: 'pix', valor: i.valor_final })),
        ...(bancosRes.data || []).map(i => ({ ...i, type: 'bank' }))
      ].sort((a, b) => new Date(b.criado_em || b.data).getTime() - new Date(a.criado_em || a.data).getTime());

      setRecentTransactions(allItems.slice(0, 5));
    } catch (err) {
      console.error("Erro ao recuperar dados:", err);
    } finally {
      setLoading(false);
    }
  };

  const formatCurrency = (val: number) => 
    new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);

  if (loading) return (
    <div className="flex flex-col items-center justify-center py-20 text-gray-400 gap-3">
      <div className="h-8 w-8 border-3 border-green-700 border-t-transparent rounded-full animate-spin"></div>
      <p className="text-xs font-bold uppercase tracking-widest">Sincronizando Saldos...</p>
    </div>
  );

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <div className="bg-green-900 text-white p-6 rounded-3xl shadow-lg relative overflow-hidden">
          <div className="absolute -right-4 -top-4 bg-white/5 p-10 rounded-full"></div>
          <p className="text-green-200/60 text-[10px] font-bold uppercase tracking-widest mb-1 flex items-center gap-1.5">
            <Wallet size={12} /> Saldo Real (Líquido)
          </p>
          <h2 className="text-3xl font-black tracking-tighter">{formatCurrency(totals.balance)}</h2>
          <p className="mt-2 text-[9px] text-green-100/40 uppercase font-bold tracking-wider">Considerando Pendências</p>
        </div>

        <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100 flex flex-col justify-between">
          <div className="flex justify-between items-start">
            <div className="bg-green-50 p-2 rounded-xl text-green-600 border border-green-100">
              <TrendingUp size={18} />
            </div>
          </div>
          <div className="mt-4">
            <p className="text-gray-400 text-[10px] font-bold uppercase tracking-widest mb-0.5">Entradas Totais</p>
            <h2 className="text-xl font-black text-gray-800">{formatCurrency(totals.revenue)}</h2>
          </div>
        </div>

        <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100 flex flex-col justify-between">
          <div className="flex justify-between items-start">
            <div className="bg-red-50 p-2 rounded-xl text-red-600 border border-red-100">
              <TrendingDown size={18} />
            </div>
          </div>
          <div className="mt-4">
            <p className="text-gray-400 text-[10px] font-bold uppercase tracking-widest mb-0.5">Saídas Totais</p>
            <h2 className="text-xl font-black text-gray-800">{formatCurrency(totals.expenses)}</h2>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
        <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100">
          <div className="flex items-center justify-between mb-5">
            <h3 className="text-sm font-bold flex items-center gap-2 text-gray-800">
              <History className="text-gray-400" size={16} />
              Lançamentos Recentes
            </h3>
          </div>
          <div className="space-y-2">
            {recentTransactions.map((item, idx) => (
              <div key={idx} className="flex items-center justify-between p-3 rounded-2xl bg-gray-50/50 border border-gray-50">
                <div className="flex items-center gap-3">
                  <div className={`p-1.5 rounded-lg ${item.type === 'revenue' ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>
                    {item.type === 'revenue' ? <TrendingUp size={14} /> : <TrendingDown size={14} />}
                  </div>
                  <div>
                    <p className="text-xs font-bold text-gray-700">{item.descricao}</p>
                    <p className="text-[9px] text-gray-400 font-bold uppercase">{new Date(item.data).toLocaleDateString('pt-BR')}</p>
                  </div>
                </div>
                <span className={`text-xs font-black ${item.type === 'revenue' ? 'text-green-700' : 'text-red-700'}`}>
                   {formatCurrency(item.valor)}
                </span>
              </div>
            ))}
          </div>
        </div>

        <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100 flex flex-col">
          <h3 className="text-sm font-bold mb-5 flex items-center gap-2 text-gray-800">
            <CalendarDays size={16} className="text-gray-400" />
            Info de Conexão
          </h3>
          <div className="space-y-3">
            <div className="p-4 bg-blue-50 border border-blue-100 rounded-2xl">
              <p className="text-[9px] font-bold text-blue-700 uppercase tracking-widest mb-1">Status do Saldo</p>
              <p className="text-[11px] text-blue-900/60 leading-relaxed font-medium">Todas as despesas, inclusive as em aberto, estão sendo subtraídas do saldo para uma visão realista.</p>
            </div>
            <button 
              onClick={refresh}
              className="w-full bg-gray-900 text-white font-bold py-3.5 rounded-2xl hover:bg-black transition shadow-md text-xs uppercase tracking-widest"
            >
              Sincronizar Banco
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Overview;

import React, { useState, useEffect } from 'react';
import { 
  LayoutDashboard, 
  Receipt, 
  TrendingUp, 
  Banknote, 
  LockKeyhole, 
  Menu, 
  Wallet,
  RefreshCw,
  CalendarClock,
  Plus,
  Clock,
  CalendarDays
} from 'lucide-react';
import { supabaseClient } from './services/supabase';
import { Month } from './types';
import Overview from './components/Overview';
import Expenses from './components/Expenses';
import Revenue from './components/Revenue';
import Banks from './components/Banks';
import Closing from './components/Closing';
import Installments from './components/Installments';

const App: React.FC = () => {
  const [view, setView] = useState<string>('overview');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [activeMonth, setActiveMonth] = useState<Month | null>(null);
  const [provisionMonth, setProvisionMonth] = useState<Month | null>(null);
  const [currentContextMonth, setCurrentContextMonth] = useState<Month | null>(null);
  const [loading, setLoading] = useState(true);
  const [refreshKey, setRefreshKey] = useState(0);
  const [triggerAdd, setTriggerAdd] = useState(0);

  useEffect(() => {
    init();
  }, []);

  const init = async () => {
    setLoading(true);
    try {
      const { data: meses } = await supabaseClient
        .from('meses')
        .select('*')
        .order('ano', { ascending: false });

      let active = meses?.find((m: Month) => m.status === 'ativo');

      // Se não houver mês ativo, inicializa com DEZEMBRO/2025 conforme solicitado
      if (!meses || meses.length === 0 || !active) {
        const { data } = await supabaseClient
          .from('meses')
          .insert([{ nome: 'DEZEMBRO', ano: 2025, status: 'ativo' }])
          .select()
          .single();
        active = data;
      }

      // Lógica de Provisionamento e Virada de Ano (Ex: Dez/2025 -> Jan/2026)
      if (active) {
        const meses_nomes = ["JANEIRO", "FEVEREIRO", "MARÇO", "ABRIL", "MAIO", "JUNHO", "JULHO", "AGOSTO", "SETEMBRO", "OUTUBRO", "NOVEMBRO", "DEZEMBRO"];
        let idx = meses_nomes.indexOf(active.nome.toUpperCase());
        let nextIdx = (idx + 1) % 12;
        let nextYear = idx === 11 ? active.ano + 1 : active.ano;
        const nextMonthName = meses_nomes[nextIdx];

        let prov = meses?.find(m => m.nome.toUpperCase() === nextMonthName && m.ano === nextYear);

        if (!prov) {
          const { data: newProv } = await supabaseClient
            .from('meses')
            .insert([{ nome: nextMonthName, ano: nextYear, status: 'provisionamento' }])
            .select()
            .single();
          prov = newProv;
        }

        setActiveMonth(active);
        setProvisionMonth(prov || null);

        // Mantém o contexto no mês atual se ele ainda for válido, senão reseta para o ativo
        if (!currentContextMonth || (currentContextMonth.id !== active.id && currentContextMonth.id !== prov?.id && currentContextMonth.status !== 'fechado')) {
          setCurrentContextMonth(active);
        }
      }
    } catch (error) {
      console.error("Erro na inicialização:", error);
    } finally {
      setLoading(false);
    }
  };

  const handleGlobalRefresh = () => {
    setRefreshKey(prev => prev + 1);
    init();
  };

  const handleNavigate = (newView: string) => {
    setView(newView);
    setIsSidebarOpen(false);
  };

  const handleContextChange = (month: Month) => {
    // White Label Reset: Força a limpeza de todo o estado mudando a key dos componentes
    setCurrentContextMonth(month);
    setRefreshKey(prev => prev + 1);
  };

  const onAddClick = () => {
    setTriggerAdd(prev => prev + 1);
  };

  if (loading || !currentContextMonth) {
    return (
      <div className="flex h-screen w-screen items-center justify-center bg-[#F8F9FA]">
        <div className="flex flex-col items-center gap-4">
          <div className="h-14 w-14 animate-spin rounded-full border-[5px] border-gray-900 border-t-transparent"></div>
          <p className="font-black text-gray-400 uppercase tracking-[0.2em] text-[10px]">Carregando Contexto...</p>
        </div>
      </div>
    );
  }

  const showAddAction = ['expenses', 'revenue', 'installments', 'banks'].includes(view);
  const canEdit = currentContextMonth.status !== 'fechado';

  return (
    <div className="flex h-screen bg-[#F8F9FA] overflow-hidden text-gray-900">
      {/* Sidebar Mobile Toggle */}
      {!isSidebarOpen && (
        <button 
          className="fixed bottom-8 left-8 z-50 p-5 bg-gray-900 text-white rounded-[2rem] shadow-2xl lg:hidden active:scale-90 transition-transform"
          onClick={() => setIsSidebarOpen(true)}
        >
          <Menu size={24} />
        </button>
      )}

      {isSidebarOpen && (
        <div className="fixed inset-0 bg-black/50 backdrop-blur-md z-30 lg:hidden" onClick={() => setIsSidebarOpen(false)} />
      )}

      {/* Navegação Lateral */}
      <aside className={`fixed inset-y-0 left-0 z-40 w-72 bg-white border-r border-gray-100 transform transition-transform duration-500 ease-in-out lg:relative lg:translate-x-0 ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'}`}>
        <div className="flex flex-col h-full p-8">
          <div className="flex items-center gap-4 mb-12">
            <div className="bg-gray-900 text-white p-3 rounded-[1.2rem] shadow-xl shadow-gray-200">
              <Wallet size={24} />
            </div>
            <div>
              <span className="text-2xl font-black tracking-tighter uppercase block leading-none">M&D</span>
              <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest leading-none">Finanças</span>
            </div>
          </div>

          <nav className="flex-1 space-y-3">
            <p className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4 ml-3">Principal</p>
            <NavItem icon={<LayoutDashboard size={22} />} label="Dashboard" active={view === 'overview'} onClick={() => handleNavigate('overview')} />
            <NavItem icon={<Receipt size={22} />} label="Despesas" active={view === 'expenses'} onClick={() => handleNavigate('expenses')} />
            <NavItem icon={<TrendingUp size={22} />} label="Receitas" active={view === 'revenue'} onClick={() => handleNavigate('revenue')} />

            <p className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em] mt-10 mb-4 ml-3">Gestão</p>
            <NavItem icon={<Banknote size={22} />} label="Cartões" active={view === 'banks'} onClick={() => handleNavigate('banks')} />
            <NavItem icon={<CalendarClock size={22} />} label="Parcelas" active={view === 'installments'} onClick={() => handleNavigate('installments')} />

            <p className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em] mt-10 mb-4 ml-3">Histórico</p>
            <NavItem icon={<Clock size={22} />} label="Arquivo" active={view === 'closing'} onClick={() => handleNavigate('closing')} />
          </nav>
        </div>
      </aside>

      {/* Área Principal */}
      <main className="flex-1 overflow-y-auto relative no-scrollbar">
        {/* HEADER LINHA DO TEMPO */}
        <div className="sticky top-0 z-20 bg-white/90 backdrop-blur-xl border-b border-gray-100 px-6 py-4 lg:px-12 lg:py-6">
          <div className="max-w-6xl mx-auto flex flex-col sm:flex-row items-center justify-between gap-6">

            {/* Context Switcher (Timeline Header) */}
            <div className="w-full sm:flex-1 flex items-center justify-between gap-2 bg-gray-100/50 p-2 rounded-[2rem] border border-gray-200/50">
              {activeMonth && (
                <button 
                  onClick={() => handleContextChange(activeMonth)}
                  className={`flex flex-col items-center justify-center min-w-[140px] px-6 py-2.5 rounded-[1.5rem] transition-all duration-300 ${
                    currentContextMonth.id === activeMonth.id 
                    ? 'bg-white shadow-xl shadow-gray-200 border border-green-100' 
                    : 'opacity-40 hover:opacity-100 hover:bg-white/50'
                  }`}
                >
                  <span className={`text-[9px] font-black uppercase tracking-widest ${currentContextMonth.id === activeMonth.id ? 'text-green-600' : 'text-gray-400'}`}>
                    Ativo
                  </span>
                  <span className="text-sm font-black text-gray-800 uppercase leading-none mt-1">
                    {activeMonth.nome} {activeMonth.ano}
                  </span>
                </button>
              )}

              {provisionMonth && (
                <button 
                  onClick={() => handleContextChange(provisionMonth)}
                  className={`flex flex-col items-center justify-center min-w-[140px] px-6 py-2.5 rounded-[1.5rem] transition-all duration-300 ${
                    currentContextMonth.id === provisionMonth.id 
                    ? 'bg-white shadow-xl shadow-gray-200 border border-blue-100' 
                    : 'opacity-40 hover:opacity-100 hover:bg-white/50'
                  }`}
                >
                  <span className={`text-[9px] font-black uppercase tracking-widest ${currentContextMonth.id === provisionMonth.id ? 'text-blue-600' : 'text-gray-400'}`}>
                    Planejamento
                  </span>
                  <span className="text-sm font-black text-gray-800 uppercase leading-none mt-1">
                    {provisionMonth.nome} {provisionMonth.ano}
                  </span>
                </button>
              )}
            </div>

            {/* Ações Globais */}
            <div className="flex items-center gap-3">
              {showAddAction && canEdit && (
                <button 
                  onClick={onAddClick}
                  className="bg-gray-900 text-white p-4 rounded-2xl shadow-xl hover:scale-105 active:scale-95 transition-all"
                  title="Novo Lançamento"
                >
                  <Plus size={22} />
                </button>
              )}
              <button 
                onClick={handleGlobalRefresh}
                className="p-4 bg-white border border-gray-200 rounded-2xl text-gray-400 hover:text-gray-900 transition-all shadow-sm"
              >
                <RefreshCw size={22} />
              </button>
            </div>
          </div>
        </div>

        {/* CONTEÚDO DINÂMICO (White Label Isolado por Mês) */}
        <div className="p-6 lg:p-12 max-w-6xl mx-auto">
          {/* Alerta de Mês Fechado */}
          {currentContextMonth.status === 'fechado' && (
            <div className="mb-10 bg-amber-50 border border-amber-200/50 p-6 rounded-[2rem] flex items-center gap-4 text-amber-800 shadow-sm animate-in fade-in slide-in-from-top-4">
              <div className="bg-amber-100 p-3 rounded-2xl"><LockKeyhole size={24} /></div>
              <div>
                <p className="text-sm font-black uppercase tracking-tighter">Histórico (Modo Leitura)</p>
                <p className="text-[11px] font-bold opacity-70 uppercase tracking-widest">Este ciclo foi encerrado. Novos dados não podem ser adicionados.</p>
              </div>
            </div>
          )}

          {/* Renderização Condicional com Reset de State via Key */}
          {view === 'overview' && <Overview key={`ov-${refreshKey}-${currentContextMonth.id}`} currentMonth={currentContextMonth} refresh={handleGlobalRefresh} />}
          {view === 'expenses' && <Expenses key={`ex-${refreshKey}-${currentContextMonth.id}`} currentMonth={currentContextMonth} triggerAdd={triggerAdd} />}
          {view === 'revenue' && <Revenue key={`rv-${refreshKey}-${currentContextMonth.id}`} currentMonth={currentContextMonth} triggerAdd={triggerAdd} />}
          {view === 'banks' && <Banks key={`bk-${refreshKey}-${currentContextMonth.id}`} currentMonth={currentContextMonth} triggerAdd={triggerAdd} />}
          {view === 'installments' && <Installments key={`in-${refreshKey}-${currentContextMonth.id}`} currentMonth={currentContextMonth} triggerAdd={triggerAdd} />}
          {view === 'closing' && <Closing key={`cl-${refreshKey}`} currentMonth={activeMonth!} onSelectMonth={handleContextChange} onRefresh={init} />}
        </div>
      </main>
    </div>
  );
};

interface NavItemProps {
  icon: React.ReactNode;
  label: string;
  active: boolean;
  onClick: () => void;
}

const NavItem: React.FC<NavItemProps> = ({ icon, label, active, onClick }) => (
  <button 
    onClick={onClick}
    className={`w-full flex items-center gap-4 px-6 py-5 rounded-2xl transition-all duration-500 font-bold text-base ${
      active 
        ? 'bg-gray-900 text-white shadow-2xl shadow-gray-400' 
        : 'text-gray-400 hover:bg-gray-50 hover:text-gray-600'
    }`}
  >
    <span className={active ? 'text-white' : 'text-gray-400'}>{icon}</span>
    <span className="uppercase tracking-widest text-xs font-black">{label}</span>
  </button>
);

export default App;

import React, { useState, useEffect } from 'react';
import { 
  LayoutDashboard, 
  Receipt, 
  TrendingUp, 
  Banknote, 
  LockKeyhole, 
  Menu, 
  Wallet,
  RefreshCw,
  CalendarClock,
  Plus,
  Clock,
  CalendarDays
} from 'lucide-react';
import { supabaseClient } from './services/supabase';
import { Month } from './types';
import Overview from './components/Overview';
import Expenses from './components/Expenses';
import Revenue from './components/Revenue';
import Banks from './components/Banks';
import Closing from './components/Closing';
import Installments from './components/Installments';

const App: React.FC = () => {
  const [view, setView] = useState<string>('overview');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [activeMonth, setActiveMonth] = useState<Month | null>(null);
  const [provisionMonth, setProvisionMonth] = useState<Month | null>(null);
  const [currentContextMonth, setCurrentContextMonth] = useState<Month | null>(null);
  const [loading, setLoading] = useState(true);
  const [refreshKey, setRefreshKey] = useState(0);
  const [triggerAdd, setTriggerAdd] = useState(0);

  useEffect(() => {
    init();
  }, []);

  const init = async () => {
    setLoading(true);
    try {
      // Busca todos os meses
      const { data: meses, error } = await supabaseClient
        .from('meses')
        .select('*')
        .order('ano', { ascending: false });

      if (error) throw error;

      let active = meses?.find((m: Month) => m.status === 'ativo');

      // Se não houver mês ativo, inicializa com DEZEMBRO/2025 (Fallback)
      if (!meses || meses.length === 0 || !active) {
        const { data } = await supabaseClient
          .from('meses')
          .insert([{ nome: 'DEZEMBRO', ano: 2025, status: 'ativo' }])
          .select()
          .single();
        active = data;
      }

      // Lógica de Provisionamento (Próximo Mês)
      if (active) {
        const meses_nomes = ["JANEIRO", "FEVEREIRO", "MARÇO", "ABRIL", "MAIO", "JUNHO", "JULHO", "AGOSTO", "SETEMBRO", "OUTUBRO", "NOVEMBRO", "DEZEMBRO"];

        // Garante que o nome do mês está limpo para comparação
        const currentName = active.nome.trim().toUpperCase();
        const idx = meses_nomes.indexOf(currentName);

        if (idx !== -1) {
          const nextIdx = (idx + 1) % 12;
          const nextYear = idx === 11 ? active.ano + 1 : active.ano;
          const nextMonthName = meses_nomes[nextIdx];

          // 1. Tenta encontrar na lista já carregada
          let prov = meses?.find(m => m.nome.trim().toUpperCase() === nextMonthName && m.ano === nextYear);

          // 2. Se não achou na memória, verifica no banco (para garantir que não existe mesmo)
          if (!prov) {
            const { data: existing } = await supabaseClient
              .from('meses')
              .select('*')
              .eq('nome', nextMonthName)
              .eq('ano', nextYear)
              .maybeSingle(); // Usa maybeSingle para evitar erro se não existir

            if (existing) {
              prov = existing;
            } else {
              // 3. Se realmente não existe, cria como provisionamento
              const { data: newProv } = await supabaseClient
                .from('meses')
                .insert([{ nome: nextMonthName, ano: nextYear, status: 'provisionamento' }])
                .select()
                .single();
              prov = newProv;
            }
          }

          setActiveMonth(active);
          setProvisionMonth(prov || null);

          // Gerencia o contexto atual (Se o contexto atual for inválido, reseta para o ativo)
          if (!currentContextMonth || (currentContextMonth.id !== active.id && currentContextMonth.id !== prov?.id && currentContextMonth.status !== 'fechado')) {
            setCurrentContextMonth(active);
          }
        }
      }
    } catch (error) {
      console.error("Erro na inicialização:", error);
    } finally {
      setLoading(false);
    }
  };

  const handleGlobalRefresh = () => {
    setRefreshKey(prev => prev + 1);
    init();
  };

  const handleNavigate = (newView: string) => {
    setView(newView);
    setIsSidebarOpen(false);
  };

  const handleContextChange = (month: Month) => {
    // White Label Reset: Força a limpeza de todo o estado mudando a key dos componentes
    setCurrentContextMonth(month);
    setRefreshKey(prev => prev + 1);
  };

  const onAddClick = () => {
    setTriggerAdd(prev => prev + 1);
  };

  if (loading || !currentContextMonth) {
    return (
      <div className="flex h-screen w-screen items-center justify-center bg-[#F8F9FA]">
        <div className="flex flex-col items-center gap-4">
          <div className="h-14 w-14 animate-spin rounded-full border-[5px] border-gray-900 border-t-transparent"></div>
          <p className="font-black text-gray-400 uppercase tracking-[0.2em] text-[10px]">Carregando Contexto...</p>
        </div>
      </div>
    );
  }

  const showAddAction = ['expenses', 'revenue', 'installments', 'banks'].includes(view);
  const canEdit = currentContextMonth.status !== 'fechado';

  return (
    <div className="flex h-screen bg-[#F8F9FA] overflow-hidden text-gray-900">
      {/* Sidebar Mobile Toggle */}
      {!isSidebarOpen && (
        <button 
          className="fixed bottom-8 left-8 z-50 p-5 bg-gray-900 text-white rounded-[2rem] shadow-2xl lg:hidden active:scale-90 transition-transform"
          onClick={() => setIsSidebarOpen(true)}
        >
          <Menu size={24} />
        </button>
      )}

      {isSidebarOpen && (
        <div className="fixed inset-0 bg-black/50 backdrop-blur-md z-30 lg:hidden" onClick={() => setIsSidebarOpen(false)} />
      )}

      {/* Navegação Lateral */}
      <aside className={`fixed inset-y-0 left-0 z-40 w-72 bg-white border-r border-gray-100 transform transition-transform duration-500 ease-in-out lg:relative lg:translate-x-0 ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'}`}>
        <div className="flex flex-col h-full p-8">
          <div className="flex items-center gap-4 mb-12">
            <div className="bg-gray-900 text-white p-3 rounded-[1.2rem] shadow-xl shadow-gray-200">
              <Wallet size={24} />
            </div>
            <div>
              <span className="text-2xl font-black tracking-tighter uppercase block leading-none">M&D</span>
              <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest leading-none">Finanças</span>
            </div>
          </div>

          <nav className="flex-1 space-y-3">
            <p className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4 ml-3">Principal</p>
            <NavItem icon={<LayoutDashboard size={22} />} label="Dashboard" active={view === 'overview'} onClick={() => handleNavigate('overview')} />
            <NavItem icon={<Receipt size={22} />} label="Despesas" active={view === 'expenses'} onClick={() => handleNavigate('expenses')} />
            <NavItem icon={<TrendingUp size={22} />} label="Receitas" active={view === 'revenue'} onClick={() => handleNavigate('revenue')} />

            <p className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em] mt-10 mb-4 ml-3">Gestão</p>
            <NavItem icon={<Banknote size={22} />} label="Cartões" active={view === 'banks'} onClick={() => handleNavigate('banks')} />
            <NavItem icon={<CalendarClock size={22} />} label="Parcelas" active={view === 'installments'} onClick={() => handleNavigate('installments')} />

            <p className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em] mt-10 mb-4 ml-3">Histórico</p>
            <NavItem icon={<Clock size={22} />} label="Arquivo" active={view === 'closing'} onClick={() => handleNavigate('closing')} />
          </nav>
        </div>
      </aside>

      {/* Área Principal */}
      <main className="flex-1 overflow-y-auto relative no-scrollbar">
        {/* HEADER LINHA DO TEMPO */}
        <div className="sticky top-0 z-20 bg-white/90 backdrop-blur-xl border-b border-gray-100 px-6 py-4 lg:px-12 lg:py-6">
          <div className="max-w-6xl mx-auto flex flex-col sm:flex-row items-center justify-between gap-6">

            {/* Context Switcher (Timeline Header) */}
            <div className="w-full sm:flex-1 flex items-center justify-between gap-2 bg-gray-100/50 p-2 rounded-[2rem] border border-gray-200/50">
              {activeMonth && (
                <button 
                  onClick={() => handleContextChange(activeMonth)}
                  className={`flex flex-col items-center justify-center min-w-[140px] px-6 py-2.5 rounded-[1.5rem] transition-all duration-300 ${
                    currentContextMonth.id === activeMonth.id 
                    ? 'bg-white shadow-xl shadow-gray-200 border border-green-100' 
                    : 'opacity-40 hover:opacity-100 hover:bg-white/50'
                  }`}
                >
                  <span className={`text-[9px] font-black uppercase tracking-widest ${currentContextMonth.id === activeMonth.id ? 'text-green-600' : 'text-gray-400'}`}>
                    Ativo
                  </span>
                  <span className="text-sm font-black text-gray-800 uppercase leading-none mt-1">
                    {activeMonth.nome} {activeMonth.ano}
                  </span>
                </button>
              )}

              {/* Renderiza o botão de planejamento se o mês existir */}
              {provisionMonth ? (
                <button 
                  onClick={() => handleContextChange(provisionMonth)}
                  className={`flex flex-col items-center justify-center min-w-[140px] px-6 py-2.5 rounded-[1.5rem] transition-all duration-300 ${
                    currentContextMonth.id === provisionMonth.id 
                    ? 'bg-white shadow-xl shadow-gray-200 border border-blue-100' 
                    : 'opacity-40 hover:opacity-100 hover:bg-white/50'
                  }`}
                >
                  <span className={`text-[9px] font-black uppercase tracking-widest ${currentContextMonth.id === provisionMonth.id ? 'text-blue-600' : 'text-gray-400'}`}>
                    Planejamento
                  </span>
                  <span className="text-sm font-black text-gray-800 uppercase leading-none mt-1">
                    {provisionMonth.nome} {provisionMonth.ano}
                  </span>
                </button>
              ) : (
                <div className="min-w-[140px] flex items-center justify-center">
                  {/* Placeholder invisível para manter layout ou indicador de carregamento */}
                  <span className="text-[9px] text-gray-300 font-bold uppercase tracking-widest animate-pulse">
                    Sincronizando...
                  </span>
                </div>
              )}
            </div>

            {/* Ações Globais */}
            <div className="flex items-center gap-3">
              {showAddAction && canEdit && (
                <button 
                  onClick={onAddClick}
                  className="bg-gray-900 text-white p-4 rounded-2xl shadow-xl hover:scale-105 active:scale-95 transition-all"
                  title="Novo Lançamento"
                >
                  <Plus size={22} />
                </button>
              )}
              <button 
                onClick={handleGlobalRefresh}
                className="p-4 bg-white border border-gray-200 rounded-2xl text-gray-400 hover:text-gray-900 transition-all shadow-sm"
              >
                <RefreshCw size={22} />
              </button>
            </div>
          </div>
        </div>

        {/* CONTEÚDO DINÂMICO (White Label Isolado por Mês) */}
        <div className="p-6 lg:p-12 max-w-6xl mx-auto">
          {/* Alerta de Mês Fechado */}
          {currentContextMonth.status === 'fechado' && (
            <div className="mb-10 bg-amber-50 border border-amber-200/50 p-6 rounded-[2rem] flex items-center gap-4 text-amber-800 shadow-sm animate-in fade-in slide-in-from-top-4">
              <div className="bg-amber-100 p-3 rounded-2xl"><LockKeyhole size={24} /></div>
              <div>
                <p className="text-sm font-black uppercase tracking-tighter">Histórico (Modo Leitura)</p>
                <p className="text-[11px] font-bold opacity-70 uppercase tracking-widest">Este ciclo foi encerrado. Novos dados não podem ser adicionados.</p>
              </div>
            </div>
          )}

          {/* Renderização Condicional com Reset de State via Key */}
          {view === 'overview' && <Overview key={`ov-${refreshKey}-${currentContextMonth.id}`} currentMonth={currentContextMonth} refresh={handleGlobalRefresh} />}
          {view === 'expenses' && <Expenses key={`ex-${refreshKey}-${currentContextMonth.id}`} currentMonth={currentContextMonth} triggerAdd={triggerAdd} />}
          {view === 'revenue' && <Revenue key={`rv-${refreshKey}-${currentContextMonth.id}`} currentMonth={currentContextMonth} triggerAdd={triggerAdd} />}
          {view === 'banks' && <Banks key={`bk-${refreshKey}-${currentContextMonth.id}`} currentMonth={currentContextMonth} triggerAdd={triggerAdd} />}
          {view === 'installments' && <Installments key={`in-${refreshKey}-${currentContextMonth.id}`} currentMonth={currentContextMonth} triggerAdd={triggerAdd} />}
          {view === 'closing' && <Closing key={`cl-${refreshKey}`} currentMonth={activeMonth!} onSelectMonth={handleContextChange} onRefresh={init} />}
        </div>
      </main>
    </div>
  );
};

interface NavItemProps {
  icon: React.ReactNode;
  label: string;
  active: boolean;
  onClick: () => void;
}

const NavItem: React.FC<NavItemProps> = ({ icon, label, active, onClick }) => (
  <button 
    onClick={onClick}
    className={`w-full flex items-center gap-4 px-6 py-5 rounded-2xl transition-all duration-500 font-bold text-base ${
      active 
        ? 'bg-gray-900 text-white shadow-2xl shadow-gray-400' 
        : 'text-gray-400 hover:bg-gray-50 hover:text-gray-600'
