function App() {
  const [months, setMonths] = useState<Month[]>([]);
  const [currentMonth, setCurrentMonth] = useState<Month | null>(null);

  useEffect(() => {
    async function loadMonths() {
      try {
        const response = await api.get('/meses');
        const monthsData = response.data as Month[];

        // Sort months by date to get the active month correctly
        monthsData.sort((a, b) => {
          return getMonthValue(a) - getMonthValue(b);
        });

        // Identify the current active month as the first
        const activeMonth = monthsData.find(month => month.status === 'ativo');

        setCurrentMonth(activeMonth || monthsData[0] || null);
        setMonths(monthsData);
      } catch (error) {
        console.error('Error fetching months:', error);
      }
    }
    loadMonths();
  }, []);

