    try {
      // Try to create with 'provisionamento' first
      await api.post('/meses', { nome: nextMonthName, ano: currentYear, status: 'provisionamento' });
      // Reload months to reflect the change
      const response = await api.get('/meses');
      const monthsData = response.data as Month[];
      monthsData.sort((a, b) => {
        return getMonthValue(a) - getMonthValue(b);
      });
      setMonths(monthsData);
    } catch (error: any) {
      if (error.response && error.response.status === 400 && error.response.data.message.includes("meses_status_check")) {
