      const statusOrder: Record<MonthStatus, number> = { 'ativo': 1, 'provisionamento': 2, 'fechado': 3 };
      const meses_nomes = ["JANEIRO", "FEVEREIRO", "MARÇO", "ABRIL", "MAIO", "JUNHO", "JULHO", "AGOSTO", "SETEMBRO", "OUTUBRO", "NOVEMBRO", "DEZEMBRO"];

      const sortedMonths = [...allMonths].sort((a, b) => {
        const statusA = statusOrder[a.status] || 99;
        const statusB = statusOrder[b.status] || 99;

        if (statusA !== statusB) return statusA - statusB;

        if (a.ano !== b.ano) return b.ano - a.ano;
        return meses_nomes.indexOf(b.nome.toUpperCase()) - meses_nomes.indexOf(a.nome.toUpperCase());
      });

      setMonths(sortedMonths);
    } catch (err) {
      console.error("Erro ao carregar histórico:", err);
    } finally {
      setLoading(false);
    }
  };

  const closeMonthRoutine = async () => {
    if (currentMonth.status !== 'ativo') {
      alert("Apenas o mês ativo pode ser encerrado.");
      return;
    }

    if (!confirm(`Deseja encerrar ${currentMonth.nome}/${currentMonth.ano}? Esta ação é irreversível e bloqueará edições.`)) return;

    console.log(`[FECHAMENTO] Iniciando rotina para: ${currentMonth.nome}`);

    const [r, d, p, b] = await Promise.all([
      supabaseClient.from('receitas').select('valor').eq('mes_id', currentMonth.id),
      supabaseClient.from('despesas_contas').select('valor').eq('mes_id', currentMonth.id).eq('pago', true),
      supabaseClient.from('despesas_pix_credito').select('valor_final').eq('mes_id', currentMonth.id).eq('pago', true),
      supabaseClient.from('banco_despesas').select('valor').eq('mes_id', currentMonth.id).eq('pago', true)
    ]);

    const rev = r.data?.reduce((a,c) => a + c.valor, 0) || 0;
    const exp = (d.data?.reduce((a,c) => a + c.valor, 0) || 0) + 
                (p.data?.reduce((a,c) => a + c.valor_final, 0) || 0) + 
                (b.data?.reduce((a,c) => a + c.valor, 0) || 0);
    const total = rev - exp;

    // 1. Fecha o mês atual
    await supabaseClient.from('meses').update({ status: 'fechado', saldo_final: total }).eq('id', currentMonth.id);

    // 2. Busca o mês de destino
    const meses_nomes = ["JANEIRO", "FEVEREIRO", "MARÇO", "ABRIL", "MAIO", "JUNHO", "JULHO", "AGOSTO", "SETEMBRO", "OUTUBRO", "NOVEMBRO", "DEZEMBRO"];
    let idx = meses_nomes.indexOf(currentMonth.nome.toUpperCase());
    let nextIdx = (idx + 1) % 12;
    let nextYear = idx === 11 ? currentMonth.ano + 1 : currentMonth.ano;
    const nextMonthName = meses_nomes[nextIdx];

    console.log(`[FECHAMENTO] Buscando destino: ${nextMonthName}/${nextYear}`);

    // Tentamos buscar o mês de destino independente de status para garantir a migração
    const { data: nextMonthData } = await supabaseClient
      .from('meses')
      .select('*')
      .eq('nome', nextMonthName)
      .eq('ano', nextYear)
      .single();

    if (!nextMonthData) {
      console.error(`[ERRO DESTINO] Não foi possível encontrar o mês ${nextMonthName}/${nextYear} no banco de dados!`);
      alert(`Erro: O mês de ${nextMonthName} não foi criado previamente.`);
      return;
    }

    console.log(`[FECHAMENTO] Destino encontrado ID: ${nextMonthData.id}. Atualizando para 'ativo'...`);
    await supabaseClient.from('meses').update({ status: 'ativo' }).eq('id', nextMonthData.id);

    // 3. Continuidade de Parcelas
    console.log(`[MIGRAÇÃO] Lendo parcelas do mês atual (ID: ${currentMonth.id})...`);
    const { data: installments, error: fetchError } = await supabaseClient
      .from('parcelas')
      .select('*')
      .eq('mes_id', currentMonth.id);

    if (fetchError) {
      console.error("[ERRO LEITURA] Falha ao ler parcelas para migração:", fetchError.message);
    }

    if (installments && installments.length > 0) {
      const pending = installments.filter(i => (i.parcela_atual || 0) < (i.total_parcelas || 0));
      console.log(`[MIGRAÇÃO] Parcelas totais: ${installments.length} | Pendentes para migrar: ${pending.length}`);

      if (pending.length > 0) {
        const carryOver = pending.map(i => ({
          mes_id: nextMonthData.id,
          descricao: i.descricao,
          valor_parcela: i.valor_parcela,
          parcela_atual: (i.parcela_atual || 0) + 1,
          total_parcelas: i.total_parcelas
        }));

        console.log(`[MIGRAÇÃO] Enviando ${carryOver.length} registros para o Mês ID: ${nextMonthData.id}`);
        console.error(`[DADO MIGRADO] Exemplo: ${carryOver[0].descricao} passará a ser ${carryOver[0].parcela_atual}/${carryOver[0].total_parcelas}`);

        const { error: insertError } = await supabaseClient.from('parcelas').insert(carryOver);
        if (insertError) {
          console.error("[ERRO INSERÇÃO] Falha ao gravar parcelas no mês seguinte:", insertError.message);
        } else {
          console.log("[MIGRAÇÃO] Sucesso! Parcelas migradas.");
        }
      } else {
        console.log("[MIGRAÇÃO] Nenhuma parcela pendente encontrada para migração.");
      }
    } else {
      console.log("[MIGRAÇÃO] O mês atual não possui parcelas registradas.");
    }

    alert(`Mês de ${currentMonth.nome} encerrado. Verifique o console para o relatório de diagnóstico.`);
    onRefresh();
    fetchMonths();
  };

  const formatCurrency = (val: number) => 
    new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);

  return (
    <div className="space-y-8 animate-in fade-in duration-700 pb-20">
      {currentMonth.status === 'ativo' && (
        <div className="bg-gray-900 p-8 sm:p-12 rounded-[2.5rem] flex flex-col md:flex-row items-center justify-between gap-8 shadow-2xl">
          <div className="flex items-center gap-6 text-white">
            <div className="bg-white/10 p-5 rounded-3xl backdrop-blur-sm border border-white/5">
              <LockKeyhole size={32} />
            </div>
            <div>
              <h3 className="text-2xl font-black uppercase tracking-tighter leading-none mb-2">Encerrar Ciclo</h3>
              <p className="text-white/40 text-xs font-bold uppercase tracking-widest max-w-xs">Finaliza {currentMonth.nome} e ativa o planejamento como novo ciclo real.</p>
            </div>
          </div>
          <button 
            onClick={closeMonthRoutine}
            className="w-full md:w-auto bg-white text-gray-900 px-10 py-5 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-gray-100 transition shadow-xl active:scale-95"
          >
            Fechar Mês Agora
          </button>
        </div>
      )}

      <div className="bg-white rounded-[2.5rem] shadow-sm border border-gray-100 p-8 lg:p-12">
        <h3 className="text-xl font-black mb-10 flex items-center gap-3 text-gray-800">
          <Calendar className="text-gray-400" size={24} />
          ARQUIVO MENSAL
        </h3>

        {loading ? (
          <div className="py-24 flex flex-col items-center gap-4">
            <div className="w-10 h-10 border-4 border-gray-900 border-t-transparent rounded-full animate-spin"></div>
            <p className="text-[10px] font-black uppercase tracking-widest text-gray-400">Varrendo Registros...</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {months.map(m => (
              <div 
                key={m.id} 
                className={`p-6 rounded-[1.8rem] border flex items-center justify-between transition-all group ${
                  m.status === 'ativo' ? 'bg-green-50/20 border-green-100' :
                  m.status === 'provisionamento' ? 'bg-blue-50/20 border-blue-100' :
                  'bg-gray-50/30 border-gray-100 hover:border-gray-200'
                }`}
              >
                <div className="flex items-center gap-5">
                  <div className={`p-4 rounded-2xl shadow-sm ${
                      m.status === 'ativo' ? 'bg-green-600 text-white' :
                      m.status === 'provisionamento' ? 'bg-blue-600 text-white' :
                      'bg-white text-gray-300 border border-gray-100'}`
                  }>
                    {m.status === 'ativo' ? <Unlock size={20} /> :
                     m.status === 'provisionamento' ? <CalendarPlus size={20} /> :
                     <LockKeyhole size={20} />}
                  </div>
                  <div>
                    <h4 className="font-black text-gray-900 text-base uppercase tracking-tight">{m.nome} {m.ano}</h4>
                    <span className={`text-[9px] font-black uppercase tracking-[0.15em] px-2.5 py-1 rounded-lg ${
                        m.status === 'ativo' ? 'bg-green-100 text-green-700' :
                        m.status === 'provisionamento' ? 'bg-blue-100 text-blue-700' :
                        'bg-gray-200 text-gray-500'}`
                    }>
                      {m.status === 'provisionamento' ? 'Planejamento' : m.status}
                    </span>
                  </div>
                </div>

                <div className="text-right">
                  {m.status === 'fechado' ? (
                    <p className="text-base font-black text-gray-900 tracking-tighter">{formatCurrency(m.saldo_final)}</p>
                  ) : (
                    <p className="text-[10px] text-gray-400 font-black uppercase tracking-widest">
                      {m.status === 'ativo' ? 'Contexto Real' : 'Fluxo Futuro'}
                    </p>
                  )}
                  <button 
                    onClick={() => onSelectMonth(m)}
                    className="mt-2 text-[10px] font-black uppercase tracking-widest flex items-center gap-1.5 ml-auto text-gray-900 hover:gap-2 transition-all"
                  >
                    ACESSAR <ChevronRight size={14} />
                  </button>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default Closing;

import React, { useState, useEffect } from 'react';
import { CalendarClock, Trash2, X as LucideX, Info, Wallet, Pencil } from 'lucide-react';
import { supabaseClient } from '../services/supabase';
import { Month, Installment } from '../types';

interface InstallmentsProps {
  currentMonth: Month;
  triggerAdd: number;
}

const Installments: React.FC<InstallmentsProps> = ({ currentMonth, triggerAdd }) => {
  const [installments, setInstallments] = useState<Installment[]>([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [editingId, setEditingId] = useState<number | null>(null);
  const [confirmDeleteId, setConfirmDeleteId] = useState<number | null>(null);
  const [formData, setFormData] = useState({ desc: '', val: 'R$ 0,00', atual: '1', total: '1' });

  useEffect(() => {
    fetchData();
  }, [currentMonth]);

  useEffect(() => {
    if (triggerAdd > 0) {
      setEditingId(null);
      setFormData({ desc: '', val: 'R$ 0,00', atual: '1', total: '1' });
      setShowModal(true);
    }
  }, [triggerAdd]);

  const fetchData = async () => {
    setLoading(true);
    try {
      // Corrigido para 'parcelamentos' conforme estrutura real do banco
      const { data, error } = await supabaseClient
        .from('parcelamentos')
        .select('*')
        .eq('mes_id', currentMonth.id);

      if (error) throw error;
      setInstallments(data || []);
    } catch (error) {
      console.error("Erro ao buscar parcelamentos:", error);
      setInstallments([]);
    } finally {
      setLoading(false);
    }
  };

  const maskCurrency = (value: string) => {
    const digits = value.replace(/\D/g, "");
    const amount = Number(digits) / 100;
    return new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(amount);
  };

  const parseCurrency = (value: string) => parseFloat(value.replace(/[^\d,]/g, '').replace(',', '.')) || 0;
  const formatCurrency = (val: number) => new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);

  const openEditModal = (item: Installment) => {
    setEditingId(item.id);
    setFormData({
      desc: item.descricao || '',
      val: maskCurrency(((item.valor_parcela || 0) * 100).toString()),
      atual: (item.parcela_atual ?? 1).toString(),
      total: (item.total_parcelas ?? 1).toString()
    });
    setShowModal(true);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const val = parseCurrency(formData.val);
    const payload = {
      mes_id: currentMonth.id,
      descricao: formData.desc,
      valor_parcela: val,
      parcela_atual: parseInt(formData.atual, 10),
      total_parcelas: parseInt(formData.total, 10)
    };

    if (editingId) {
      await supabaseClient.from('parcelamentos').update(payload).eq('id', editingId);
    } else {
      await supabaseClient.from('parcelamentos').insert([payload]);
    }

    setShowModal(false);
    setEditingId(null);
    fetchData();
  };

  const handleDelete = async (id: number) => {
    await supabaseClient.from('parcelamentos').delete().eq('id', id);
    setConfirmDeleteId(null);
    fetchData();
  };

  const canEdit = currentMonth.status !== 'fechado' && currentMonth.id !== -1;

  return (
    <div className="space-y-4 animate-in fade-in duration-300">
      {loading ? (
        <div className="py-20 flex flex-col items-center gap-3 text-gray-400">
          <div className="w-8 h-8 border-3 border-green-700 border-t-transparent rounded-full animate-spin"></div>
          <p className="font-bold uppercase tracking-widest text-[9px]">Sincronizando...</p>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
          {installments.length === 0 ? (
            <div className="col-span-full py-20 bg-white rounded-3xl border border-dashed border-gray-200 flex flex-col items-center justify-center text-gray-400">
              <CalendarClock size={32} className="mb-2 opacity-20" />
              <p className="font-bold uppercase tracking-widest text-[10px]">Sem parcelas ativas para {currentMonth.nome}</p>
            </div>
          ) : (
            installments.map(item => {
              const pAtual = item.parcela_atual ?? 1;
              const pTotal = item.total_parcelas ?? 1;
              const pValor = item.valor_parcela ?? 0;
              const parcelasPendentes = Math.max(0, (pTotal - pAtual + 1));
              const totalQuitacao = pValor * parcelasPendentes;

              return (
                <div key={item.id} className="bg-white rounded-3xl p-5 border border-gray-100 shadow-sm flex flex-col">
                  <div className="flex justify-between items-start mb-4">
                    <div className="flex items-center gap-3 min-w-0">
                      <div className="bg-blue-50 p-2 rounded-xl text-blue-600 shrink-0"><CalendarClock size={18} /></div>
                      <div className="min-w-0">
                        <h4 className="font-bold text-gray-800 text-sm truncate">{item.descricao}</h4>
                        <p className="text-[9px] text-gray-400 font-bold uppercase tracking-widest">Progresso: {pAtual}/{pTotal}</p>
                      </div>
                    </div>
                    {canEdit && (
                      <div className="flex items-center">
                        <button onClick={() => openEditModal(item)} className="text-gray-300 hover:text-blue-600 p-1.5"><Pencil size={16} /></button>
                        {confirmDeleteId === item.id ? (
                          <button onClick={() => handleDelete(item.id)} className="text-red-600 font-black text-[9px] uppercase px-2">Sim</button>
                        ) : (
                          <button onClick={() => setConfirmDeleteId(item.id)} className="text-gray-300 hover:text-red-500 p-1.5"><Trash2 size={16} /></button>
                        )}
                      </div>
                    )}
                  </div>

                  <div className="grid grid-cols-2 gap-2 mb-4">
                    <div className="bg-gray-50/50 p-3 rounded-2xl border border-gray-50">
                      <p className="text-[8px] font-black text-gray-400 uppercase tracking-widest mb-0.5">Vl Parcela</p>
                      <p className="text-sm font-black text-gray-800">{formatCurrency(pValor)}</p>
                    </div>
                    <div className="bg-gray-50/50 p-3 rounded-2xl border border-gray-50">
                      <p className="text-[8px] font-black text-gray-400 uppercase tracking-widest mb-0.5">Restantes</p>
                      <p className="text-sm font-black text-gray-800">{parcelasPendentes}x</p>
                    </div>
                  </div>

                  <div className="mt-auto bg-green-800 p-4 rounded-2xl text-white">
                    <p className="text-[8px] font-bold text-green-200 uppercase tracking-widest mb-0.5">Quitação Total</p>
                    <div className="flex items-center justify-between">
                      <span className="text-lg font-black tracking-tight">{formatCurrency(totalQuitacao)}</span>
                      <Wallet size={16} className="opacity-30" />
                    </div>
                  </div>
                </div>
              );
            })
          )}
        </div>
      )}

      {showModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
          <div className="bg-white w-full max-w-sm p-6 rounded-3xl shadow-2xl animate-in zoom-in duration-200">
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-lg font-black text-gray-900 uppercase tracking-tight">{editingId ? 'Editar' : 'Novo'} Parcelamento</h2>
              <button onClick={() => setShowModal(false)} className="text-gray-400"><LucideX size={20} /></button>
            </div>
            <form onSubmit={handleSubmit} className="space-y-4">
              <div>
                <label className="block text-[9px] font-bold text-gray-400 uppercase mb-1.5 tracking-widest">Descrição</label>
                <input type="text" value={formData.desc} onChange={e => setFormData({...formData, desc: e.target.value})} className="w-full bg-gray-50 border border-gray-200 rounded-xl px-4 py-2.5 outline-none focus:border-green-700 font-bold text-sm" placeholder="Notebook..." required />
              </div>
              <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
                <div className="sm:col-span-1">
                  <label className="block text-[9px] font-bold text-gray-400 uppercase mb-1.5 tracking-widest">Valor</label>
                  <input type="text" inputMode="numeric" value={formData.val} onChange={e => setFormData({...formData, val: maskCurrency(e.target.value)})} className="w-full bg-gray-50 border border-gray-200 rounded-xl px-4 py-2.5 outline-none focus:border-green-700 font-black text-sm" required />
                </div>
                <div>
                  <label className="block text-[9px] font-bold text-gray-400 uppercase mb-1.5 tracking-widest">Atual</label>
                  <input type="number" min="1" value={formData.atual} onChange={e => setFormData({...formData, atual: e.target.value})} className="w-full bg-gray-50 border border-gray-200 rounded-xl px-4 py-2.5 outline-none focus:border-green-700 font-black text-center text-sm" required />
                </div>
                <div>
                  <label className="block text-[9px] font-bold text-gray-400 uppercase mb-1.5 tracking-widest">Total</label>
                  <input type="number" min="1" value={formData.total} onChange={e => setFormData({...formData, total: e.target.value})} className="w-full bg-gray-50 border border-gray-200 rounded-xl px-4 py-2.5 outline-none focus:border-green-700 font-black text-center text-sm" required />
                </div>
              </div>
              <div className="bg-blue-50 p-3 rounded-xl border border-blue-100 flex items-start gap-2">
                <Info size={14} className="text-blue-600 shrink-0" />
                <p className="text-[9px] font-bold text-blue-800 leading-tight uppercase">O sistema gerencia automaticamente a progressão das parcelas ao fechar o mês.</p>
              </div>
              <div className="flex gap-3 pt-3">
                <button type="button" onClick={() => setShowModal(false)} className="flex-1 bg-gray-100 text-gray-500 font-bold py-3.5 rounded-xl uppercase text-[10px] tracking-widest">Sair</button>
                <button type="submit" className="flex-1 bg-green-800 text-white font-bold py-3.5 rounded-xl shadow-md uppercase text-[10px] tracking-widest">Salvar</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Installments;

import React, { useState, useEffect } from 'react';
import { LockKeyhole, Unlock, Calendar, TrendingUp, CalendarPlus, ChevronRight } from 'lucide-react';
import { supabaseClient } from '../services/supabase';
import { Month, MonthStatus } from '../types';

interface ClosingProps {
  currentMonth: Month;
  onSelectMonth: (month: Month) => void;
  onRefresh: () => void;
}

const Closing: React.FC<ClosingProps> = ({ currentMonth, onSelectMonth, onRefresh }) => {
  const [months, setMonths] = useState<Month[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchMonths();
  }, []);

  const fetchMonths = async () => {
    setLoading(true);
    try {
      let { data: allMonths, error } = await supabaseClient
        .from('meses')
        .select('*')
        .order('ano', { ascending: false });

      if (error || !allMonths) {
        setMonths([]);
        setLoading(false);
        return;
      }

      const statusOrder: Record<MonthStatus, number> = { 'ativo': 1, 'provisionamento': 2, 'fechado': 3 };
      const meses_nomes = ["JANEIRO", "FEVEREIRO", "MARÇO", "ABRIL", "MAIO", "JUNHO", "JULHO", "AGOSTO", "SETEMBRO", "OUTUBRO", "NOVEMBRO", "DEZEMBRO"];

      const sortedMonths = [...allMonths].sort((a, b) => {
        const statusA = statusOrder[a.status] || 99;
        const statusB = statusOrder[b.status] || 99;

        if (statusA !== statusB) return statusA - statusB;

        if (a.ano !== b.ano) return b.ano - a.ano;
        return meses_nomes.indexOf(b.nome.toUpperCase()) - meses_nomes.indexOf(a.nome.toUpperCase());
      });

      setMonths(sortedMonths);
    } catch (err) {
      console.error("Erro ao carregar histórico:", err);
    } finally {
      setLoading(false);
    }
  };

  const closeMonthRoutine = async () => {
    if (currentMonth.status !== 'ativo') {
      alert("Apenas o mês ativo pode ser encerrado.");
      return;
    }

    if (!confirm(`Deseja encerrar ${currentMonth.nome}/${currentMonth.ano}? Esta ação é irreversível e bloqueará edições.`)) return;

    const [r, d, p, b] = await Promise.all([
      supabaseClient.from('receitas').select('valor').eq('mes_id', currentMonth.id),
      supabaseClient.from('despesas_contas').select('valor').eq('mes_id', currentMonth.id).eq('pago', true),
      supabaseClient.from('despesas_pix_credito').select('valor_final').eq('mes_id', currentMonth.id).eq('pago', true),
      supabaseClient.from('banco_despesas').select('valor').eq('mes_id', currentMonth.id).eq('pago', true)
    ]);

    const rev = r.data?.reduce((a,c) => a + c.valor, 0) || 0;
    const exp = (d.data?.reduce((a,c) => a + c.valor, 0) || 0) + 
                (p.data?.reduce((a,c) => a + c.valor_final, 0) || 0) + 
                (b.data?.reduce((a,c) => a + c.valor, 0) || 0);
    const total = rev - exp;

    // 1. Fecha o mês atual
    await supabaseClient.from('meses').update({ status: 'fechado', saldo_final: total }).eq('id', currentMonth.id);

    // 2. Busca o mês de destino
    const meses_nomes = ["JANEIRO", "FEVEREIRO", "MARÇO", "ABRIL", "MAIO", "JUNHO", "JULHO", "AGOSTO", "SETEMBRO", "OUTUBRO", "NOVEMBRO", "DEZEMBRO"];
    let idx = meses_nomes.indexOf(currentMonth.nome.toUpperCase());
    let nextIdx = (idx + 1) % 12;
    let nextYear = idx === 11 ? currentMonth.ano + 1 : currentMonth.ano;
    const nextMonthName = meses_nomes[nextIdx];

    const { data: nextMonthData } = await supabaseClient
      .from('meses')
      .select('*')
      .eq('nome', nextMonthName)
      .eq('ano', nextYear)
      .single();

    if (!nextMonthData) {
      alert(`Erro: O mês de ${nextMonthName} não foi encontrado para migração.`);
      return;
    }

    // Ativa o próximo mês se necessário
    await supabaseClient.from('meses').update({ status: 'ativo' }).eq('id', nextMonthData.id);

    // 3. Continuidade de Parcelas (Tabela: parcelamentos)
    const { data: installments } = await supabaseClient
      .from('parcelamentos')
      .select('*')
      .eq('mes_id', currentMonth.id);

    if (installments && installments.length > 0) {
      const pending = installments.filter(i => (i.parcela_atual || 0) < (i.total_parcelas || 0));

      if (pending.length > 0) {
        const carryOver = pending.map(i => ({
          mes_id: nextMonthData.id,
          descricao: i.descricao,
          valor_parcela: i.valor_parcela,
          parcela_atual: (i.parcela_atual || 0) + 1,
          total_parcelas: i.total_parcelas
        }));

        const { error: insertError } = await supabaseClient.from('parcelamentos').insert(carryOver);
        if (insertError) console.error("Falha ao migrar parcelas:", insertError.message);
      }
    }

    alert(`Mês de ${currentMonth.nome} encerrado. O novo ciclo começou.`);
    onRefresh();
    fetchMonths();
  };

  const formatCurrency = (val: number) => 
    new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);

  return (
    <div className="space-y-8 animate-in fade-in duration-700 pb-20">
      {currentMonth.status === 'ativo' && (
        <div className="bg-gray-900 p-8 sm:p-12 rounded-[2.5rem] flex flex-col md:flex-row items-center justify-between gap-8 shadow-2xl">
          <div className="flex items-center gap-6 text-white">
            <div className="bg-white/10 p-5 rounded-3xl backdrop-blur-sm border border-white/5">
              <LockKeyhole size={32} />
            </div>
            <div>
              <h3 className="text-2xl font-black uppercase tracking-tighter leading-none mb-2">Encerrar Ciclo</h3>
              <p className="text-white/40 text-xs font-bold uppercase tracking-widest max-w-xs">Finaliza {currentMonth.nome} e ativa o planejamento como novo ciclo real.</p>
            </div>
          </div>
          <button 
            onClick={closeMonthRoutine}
            className="w-full md:w-auto bg-white text-gray-900 px-10 py-5 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-gray-100 transition shadow-xl active:scale-95"
          >
            Fechar Mês Agora
          </button>
        </div>
      )}

      <div className="bg-white rounded-[2.5rem] shadow-sm border border-gray-100 p-8 lg:p-12">
        <h3 className="text-xl font-black mb-10 flex items-center gap-3 text-gray-800">
          <Calendar className="text-gray-400" size={24} />
          ARQUIVO MENSAL
        </h3>

        {loading ? (
          <div className="py-24 flex flex-col items-center gap-4">
            <div className="w-10 h-10 border-4 border-gray-900 border-t-transparent rounded-full animate-spin"></div>
            <p className="text-[10px] font-black uppercase tracking-widest text-gray-400">Varrendo Registros...</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {months.map(m => (
              <div 
                key={m.id} 
                className={`p-6 rounded-[1.8rem] border flex items-center justify-between transition-all group ${
                  m.status === 'ativo' ? 'bg-green-50/20 border-green-100' :
                  m.status === 'provisionamento' ? 'bg-blue-50/20 border-blue-100' :
                  'bg-gray-50/30 border-gray-100 hover:border-gray-200'
                }`}
              >
                <div className="flex items-center gap-5">
                  <div className={`p-4 rounded-2xl shadow-sm ${
                      m.status === 'ativo' ? 'bg-green-600 text-white' :
                      m.status === 'provisionamento' ? 'bg-blue-600 text-white' :
                      'bg-white text-gray-300 border border-gray-100'}`
                  }>
                    {m.status === 'ativo' ? <Unlock size={20} /> :
                     m.status === 'provisionamento' ? <CalendarPlus size={20} /> :
                     <LockKeyhole size={20} />}
                  </div>
                  <div>
                    <h4 className="font-black text-gray-900 text-base uppercase tracking-tight">{m.nome} {m.ano}</h4>
                    <span className={`text-[9px] font-black uppercase tracking-[0.15em] px-2.5 py-1 rounded-lg ${
                        m.status === 'ativo' ? 'bg-green-100 text-green-700' :
                        m.status === 'provisionamento' ? 'bg-blue-100 text-blue-700' :
                        'bg-gray-200 text-gray-500'}`
                    }>
                      {m.status === 'provisionamento' ? 'Planejamento' : m.status}
                    </span>
                  </div>
                </div>

                <div className="text-right">
                  {m.status === 'fechado' ? (
                    <p className="text-base font-black text-gray-900 tracking-tighter">{formatCurrency(m.saldo_final)}</p>
                  ) : (
                    <p className="text-[10px] text-gray-400 font-black uppercase tracking-widest">
                      {m.status === 'ativo' ? 'Contexto Real' : 'Fluxo Futuro'}
                    </p>
                  )}
                  <button 
                    onClick={() => onSelectMonth(m)}
                    className="mt-2 text-[10px] font-black uppercase tracking-widest flex items-center gap-1.5 ml-auto text-gray-900 hover:gap-2 transition-all"
                  >
                    ACESSAR <ChevronRight size={14} />
                  </button>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

