                      <p className="text-xs font-bold text-gray-700 truncate max-w-[150px]">{item.descricao}</p>
                      <p className="text-[9px] text-gray-400 font-bold uppercase">{item.data ? new Date(item.data).toLocaleDateString('pt-BR') : 'Data n/a'}</p>
