import React, { useState, useEffect } from 'react';
import { LockKeyhole, Unlock, Calendar, TrendingUp, CalendarPlus, ChevronRight } from 'lucide-react';
import { supabaseClient } from '../services/supabase';
import { Month, MonthStatus } from '../types';

interface ClosingProps {
  currentMonth: Month;
  onSelectMonth: (month: Month) => void;
  onRefresh: () => void;
}

const Closing: React.FC<ClosingProps> = ({ currentMonth, onSelectMonth, onRefresh }) => {
  const [months, setMonths] = useState<Month[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchMonths();
  }, []);

  const fetchMonths = async () => {
    setLoading(true);
    try {
      let { data: allMonths, error } = await supabaseClient
        .from('meses')
        .select('*')
        .order('ano', { ascending: false });

      if (error || !allMonths) {
        setMonths([]);
        setLoading(false);
        return;
      }

      const statusOrder: Record<MonthStatus, number> = { 'ativo': 1, 'provisionamento': 2, 'fechado': 3 };
      const meses_nomes = ["JANEIRO", "FEVEREIRO", "MARÇO", "ABRIL", "MAIO", "JUNHO", "JULHO", "AGOSTO", "SETEMBRO", "OUTUBRO", "NOVEMBRO", "DEZEMBRO"];

      const sortedMonths = [...allMonths].sort((a, b) => {
        const statusA = statusOrder[a.status] || 99;
        const statusB = statusOrder[b.status] || 99;

        if (statusA !== statusB) return statusA - statusB;

        if (a.ano !== b.ano) return b.ano - a.ano;
        return meses_nomes.indexOf(b.nome.toUpperCase()) - meses_nomes.indexOf(a.nome.toUpperCase());
      });

      setMonths(sortedMonths);
    } catch (err) {
      console.error("Erro ao carregar histórico:", err);
    } finally {
      setLoading(false);
    }
  };

  const closeMonthRoutine = async () => {
    if (currentMonth.status !== 'ativo') {
      alert("Apenas o mês ativo pode ser encerrado.");
      return;
    }

    if (!confirm(`Deseja encerrar ${currentMonth.nome}/${currentMonth.ano}? As parcelas pendentes serão migradas para o próximo mês.`)) return;

    // Cálculos de saldo
    const [r, d, p, b] = await Promise.all([
      supabaseClient.from('receitas').select('valor').eq('mes_id', currentMonth.id),
      supabaseClient.from('despesas_contas').select('valor').eq('mes_id', currentMonth.id).eq('pago', true),
      supabaseClient.from('despesas_pix_credito').select('valor_final').eq('mes_id', currentMonth.id).eq('pago', true),
      supabaseClient.from('banco_despesas').select('valor').eq('mes_id', currentMonth.id).eq('pago', true)
    ]);

    const rev = r.data?.reduce((a,c) => a + c.valor, 0) || 0;
    const exp = (d.data?.reduce((a,c) => a + c.valor, 0) || 0) + 
                (p.data?.reduce((a,c) => a + c.valor_final, 0) || 0) + 
                (b.data?.reduce((a,c) => a + c.valor, 0) || 0);
    const total = rev - exp;

    // 1. Fecha o mês atual
    await supabaseClient.from('meses').update({ status: 'fechado', saldo_final: total }).eq('id', currentMonth.id);

    // 2. Localiza o próximo mês
    const meses_nomes = ["JANEIRO", "FEVEREIRO", "MARÇO", "ABRIL", "MAIO", "JUNHO", "JULHO", "AGOSTO", "SETEMBRO", "OUTUBRO", "NOVEMBRO", "DEZEMBRO"];
    let idx = meses_nomes.indexOf(currentMonth.nome.toUpperCase());
    let nextIdx = (idx + 1) % 12;
    let nextYear = idx === 11 ? currentMonth.ano + 1 : currentMonth.ano;
    const nextMonthName = meses_nomes[nextIdx];

    const { data: nextMonths } = await supabaseClient
      .from('meses')
      .select('*')
      .eq('nome', nextMonthName)
      .eq('ano', nextYear);

    const nextMonthData = nextMonths?.[0];

    if (!nextMonthData) {
      alert(`Erro crítico: O mês de ${nextMonthName}/${nextYear} não foi encontrado. A migração de parcelas falhou.`);
      onRefresh();
      return;
    }

    // Ativa o próximo mês
    await supabaseClient.from('meses').update({ status: 'ativo' }).eq('id', nextMonthData.id);

    // 3. Migração de Parcelamentos
    const { data: installments } = await supabaseClient
      .from('parcelamentos')
      .select('*')
      .eq('mes_id', currentMonth.id);

    if (installments && installments.length > 0) {
      // Filtra parcelas que ainda não chegaram ao fim
      const pending = installments.filter(i => (i.parcela_atual || 0) < (i.total_parcelas || 0));

      if (pending.length > 0) {
        const carryOver = pending.map(i => ({
          mes_id: nextMonthData.id,
          descricao: i.descricao,
          valor_parcela: i.valor_parcela,
          parcela_atual: (i.parcela_atual || 0) + 1, // Incrementa a parcela
          total_parcelas: i.total_parcelas
        }));

        const { error: insertError } = await supabaseClient.from('parcelamentos').insert(carryOver);
        if (insertError) console.error("Erro na migração:", insertError.message);
      }
    }

    alert(`Ciclo de ${currentMonth.nome} encerrado. ${nextMonthName} agora é o ciclo ativo.`);
    onRefresh();
    fetchMonths();
  };

  const formatCurrency = (val: number) => 
    new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);

  return (
    <div className="space-y-8 animate-in fade-in duration-700 pb-20">
      {currentMonth.status === 'ativo' && (
        <div className="bg-gray-900 p-8 sm:p-12 rounded-[2.5rem] flex flex-col md:flex-row items-center justify-between gap-8 shadow-2xl">
          <div className="flex items-center gap-6 text-white">
            <div className="bg-white/10 p-5 rounded-3xl backdrop-blur-sm border border-white/5">
              <LockKeyhole size={32} />
            </div>
            <div>
              <h3 className="text-2xl font-black uppercase tracking-tighter leading-none mb-2">Encerrar Ciclo</h3>
              <p className="text-white/40 text-xs font-bold uppercase tracking-widest max-w-xs">Transfere parcelas para {currentMonth.nome === 'DEZEMBRO' ? 'JANEIRO' : 'o próximo mês'} e bloqueia edições.</p>
            </div>
          </div>
          <button 
            onClick={closeMonthRoutine}
            className="w-full md:w-auto bg-white text-gray-900 px-10 py-5 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-gray-100 transition shadow-xl active:scale-95"
          >
            Fechar Mês Agora
          </button>
        </div>
      )}

      <div className="bg-white rounded-[2.5rem] shadow-sm border border-gray-100 p-8 lg:p-12">
        <h3 className="text-xl font-black mb-10 flex items-center gap-3 text-gray-800">
          <Calendar className="text-gray-400" size={24} />
          ARQUIVO MENSAL
        </h3>

        {loading ? (
          <div className="py-24 flex flex-col items-center gap-4">
            <div className="w-10 h-10 border-4 border-gray-900 border-t-transparent rounded-full animate-spin"></div>
            <p className="text-[10px] font-black uppercase tracking-widest text-gray-400">Varrendo Arquivos...</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {months.map(m => (
              <div 
                key={m.id} 
                className={`p-6 rounded-[1.8rem] border flex items-center justify-between transition-all group ${
                  m.status === 'ativo' ? 'bg-green-50/20 border-green-100' :
                  m.status === 'provisionamento' ? 'bg-blue-50/20 border-blue-100' :
                  'bg-gray-50/30 border-gray-100 hover:border-gray-200'
                }`}
              >
                <div className="flex items-center gap-5">
                  <div className={`p-4 rounded-2xl shadow-sm ${
                      m.status === 'ativo' ? 'bg-green-600 text-white' :
                      m.status === 'provisionamento' ? 'bg-blue-600 text-white' :
                      'bg-white text-gray-300 border border-gray-100'}`
                  }>
                    {m.status === 'ativo' ? <Unlock size={20} /> :
                     m.status === 'provisionamento' ? <CalendarPlus size={20} /> :
                     <LockKeyhole size={20} />}
                  </div>
                  <div>
                    <h4 className="font-black text-gray-900 text-base uppercase tracking-tight">{m.nome} {m.ano}</h4>
                    <span className={`text-[9px] font-black uppercase tracking-[0.15em] px-2.5 py-1 rounded-lg ${
                        m.status === 'ativo' ? 'bg-green-100 text-green-700' :
                        m.status === 'provisionamento' ? 'bg-blue-100 text-blue-700' :
                        'bg-gray-200 text-gray-500'}`
                    }>
                      {m.status === 'provisionamento' ? 'Planejamento' : m.status}
                    </span>
                  </div>
                </div>

                <div className="text-right">
                  {m.status === 'fechado' ? (
                    <p className="text-base font-black text-gray-900 tracking-tighter">{formatCurrency(m.saldo_final)}</p>
                  ) : (
                    <p className="text-[10px] text-gray-400 font-black uppercase tracking-widest">
                      {m.status === 'ativo' ? 'Atual' : 'Planejamento'}
                    </p>
                  )}
                  <button 
                    onClick={() => onSelectMonth(m)}
                    className="mt-2 text-[10px] font-black uppercase tracking-widest flex items-center gap-1.5 ml-auto text-gray-900 hover:gap-2 transition-all"
                  >
                    ACESSAR <ChevronRight size={14} />
                  </button>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default Closing;

import React, { useState, useEffect } from 'react';
import { TrendingDown, TrendingUp, Wallet, History, CalendarDays, CalendarClock } from 'lucide-react';
import { supabaseClient } from '../services/supabase';
import { Month } from '../types';

interface OverviewProps {
  currentMonth: Month;
  refresh: () => void;
}

const Overview: React.FC<OverviewProps> = ({ currentMonth, refresh }) => {
  const [totals, setTotals] = useState({ revenue: 0, expenses: 0, balance: 0 });
  const [recentTransactions, setRecentTransactions] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchData();
  }, [currentMonth]);

  const fetchData = async () => {
    setLoading(true);
    try {
      const [receitasRes, despesasRes, pixRes, bancosRes, parcelasRes] = await Promise.all([
        supabaseClient.from('receitas').select('valor, descricao, data, criado_em').eq('mes_id', currentMonth.id),
        supabaseClient.from('despesas_contas').select('valor, descricao, data, criado_em, pago').eq('mes_id', currentMonth.id),
        supabaseClient.from('despesas_pix_credito').select('valor_final, descricao, data, criado_em, pago').eq('mes_id', currentMonth.id),
        supabaseClient.from('banco_despesas').select('valor, descricao, data, criado_em, pago').eq('mes_id', currentMonth.id),
        supabaseClient.from('parcelamentos').select('valor_parcela, descricao, parcela_atual, total_parcelas, criado_em').eq('mes_id', currentMonth.id)
      ]);

      const rev = receitasRes.data?.reduce((acc, curr) => acc + curr.valor, 0) || 0;

      const expContas = despesasRes.data?.reduce((acc, curr) => acc + curr.valor, 0) || 0;
      const expPix = pixRes.data?.reduce((acc, curr) => acc + curr.valor_final, 0) || 0;
      const expBancos = bancosRes.data?.reduce((acc, curr) => acc + curr.valor, 0) || 0;
      const expParcelas = parcelasRes.data?.reduce((acc, curr) => acc + curr.valor_parcela, 0) || 0;

      const totalExp = expContas + expPix + expBancos + expParcelas;

      setTotals({
        revenue: rev,
        expenses: totalExp,
        balance: rev - totalExp
      });

      const allItems = [
        ...(receitasRes.data || []).map(i => ({ ...i, type: 'revenue' })),
        ...(despesasRes.data || []).map(i => ({ ...i, type: 'expense' })),
        ...(pixRes.data || []).map(i => ({ ...i, type: 'pix', valor: i.valor_final })),
        ...(bancosRes.data || []).map(i => ({ ...i, type: 'bank' })),
        ...(parcelasRes.data || []).map(i => ({ 
          ...i, 
          type: 'installment', 
          valor: i.valor_parcela, 
          descricao: `${i.descricao} (${i.parcela_atual}/${i.total_parcelas})`,
          data: i.criado_em 
        }))
      ].sort((a, b) => new Date(b.criado_em || b.data).getTime() - new Date(a.criado_em || a.data).getTime());

      setRecentTransactions(allItems.slice(0, 6));
    } catch (err) {
      console.error("Erro ao recuperar dados:", err);
    } finally {
      setLoading(false);
    }
  };

  const formatCurrency = (val: number) => 
    new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);

  if (loading) return (
    <div className="flex flex-col items-center justify-center py-20 text-gray-400 gap-3">
      <div className="h-8 w-8 border-3 border-green-700 border-t-transparent rounded-full animate-spin"></div>
      <p className="text-xs font-bold uppercase tracking-widest">Sincronizando Saldos...</p>
    </div>
  );

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <div className="bg-gray-900 text-white p-6 rounded-3xl shadow-lg relative overflow-hidden">
          <div className="absolute -right-4 -top-4 bg-white/5 p-10 rounded-full"></div>
          <p className="text-gray-400 text-[10px] font-bold uppercase tracking-widest mb-1 flex items-center gap-1.5">
            <Wallet size={12} className="text-green-500" /> Saldo Real (Líquido)
          </p>
          <h2 className="text-3xl font-black tracking-tighter">{formatCurrency(totals.balance)}</h2>
          <p className="mt-2 text-[9px] text-white/30 uppercase font-bold tracking-wider">Considerando Parcelamentos</p>
        </div>

        <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100 flex flex-col justify-between">
          <div className="flex justify-between items-start">
            <div className="bg-green-50 p-2 rounded-xl text-green-600 border border-green-100">
              <TrendingUp size={18} />
            </div>
          </div>
          <div className="mt-4">
            <p className="text-gray-400 text-[10px] font-bold uppercase tracking-widest mb-0.5">Entradas Totais</p>
            <h2 className="text-xl font-black text-gray-800">{formatCurrency(totals.revenue)}</h2>
          </div>
        </div>

        <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100 flex flex-col justify-between">
          <div className="flex justify-between items-start">
            <div className="bg-red-50 p-2 rounded-xl text-red-600 border border-red-100">
              <TrendingDown size={18} />
            </div>
          </div>
          <div className="mt-4">
            <p className="text-gray-400 text-[10px] font-bold uppercase tracking-widest mb-0.5">Saídas Totais</p>
            <h2 className="text-xl font-black text-gray-800">{formatCurrency(totals.expenses)}</h2>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
        <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100">
          <div className="flex items-center justify-between mb-5">
            <h3 className="text-sm font-bold flex items-center gap-2 text-gray-800">
              <History className="text-gray-400" size={16} />
              Movimentações Recentes
            </h3>
          </div>
          <div className="space-y-2">
            {recentTransactions.map((item, idx) => (
              <div key={idx} className="flex items-center justify-between p-3 rounded-2xl bg-gray-50/50 border border-gray-50">
                <div className="flex items-center gap-3">
                  <div className={`p-1.5 rounded-lg ${
                    item.type === 'revenue' ? 'bg-green-100 text-green-700' : 
                    item.type === 'installment' ? 'bg-blue-100 text-blue-700' : 
                    'bg-red-100 text-red-700'
                  }`}>
                    {item.type === 'revenue' ? <TrendingUp size={14} /> : 
                     item.type === 'installment' ? <CalendarClock size={14} /> : 
                     <TrendingDown size={14} />}
                  </div>
                  <div>
                    <p className="text-xs font-bold text-gray-700 truncate max-w-[150px]">{item.descricao}</p>
                    <p className="text-[9px] text-gray-400 font-bold uppercase">{item.data ? new Date(item.data).toLocaleDateString('pt-BR') : 'Sem data'}</p>
                  </div>
                </div>
                <span className={`text-xs font-black ${item.type === 'revenue' ? 'text-green-700' : 'text-red-700'}`}>
                   {item.type === 'revenue' ? '+' : '-'}{formatCurrency(item.valor)}
                </span>
              </div>
            ))}
          </div>
        </div>

        <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100 flex flex-col">
          <h3 className="text-sm font-bold mb-5 flex items-center gap-2 text-gray-800">
            <CalendarDays size={16} className="text-gray-400" />
            Informação de Parcelas
          </h3>
          <div className="space-y-3">
            <div className="p-4 bg-blue-50 border border-blue-100 rounded-2xl">
              <p className="text-[9px] font-bold text-blue-700 uppercase tracking-widest mb-1">Dedução Automática</p>
              <p className="text-[11px] text-blue-900/60 leading-relaxed font-medium">As parcelas ativas deste mês já estão sendo subtraídas do seu saldo total para evitar surpresas no fechamento.</p>
            </div>
            <button 
              onClick={refresh}
              className="w-full bg-gray-900 text-white font-bold py-3.5 rounded-2xl hover:bg-black transition shadow-md text-xs uppercase tracking-widest"
            >
              Atualizar Dashboard
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Overview;

import React, { useState, useEffect } from 'react';
import { LockKeyhole, Unlock, Calendar, TrendingUp, CalendarPlus, ChevronRight } from 'lucide-react';
import { supabaseClient } from '../services/supabase';
import { Month, MonthStatus } from '../types';

interface ClosingProps {
  currentMonth: Month;
  onSelectMonth: (month: Month) => void;
  onRefresh: () => void;
}

const Closing: React.FC<ClosingProps> = ({ currentMonth, onSelectMonth, onRefresh }) => {
  const [months, setMonths] = useState<Month[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchMonths();
  }, []);

  const fetchMonths = async () => {
    setLoading(true);
    try {
      let { data: allMonths, error } = await supabaseClient
        .from('meses')
        .select('*')
        .order('ano', { ascending: false });

      if (error || !allMonths) {
        setMonths([]);
        setLoading(false);
        return;
      }

      const statusOrder: Record<MonthStatus, number> = { 'ativo': 1, 'provisionamento': 2, 'fechado': 3 };
      const meses_nomes = ["JANEIRO", "FEVEREIRO", "MARÇO", "ABRIL", "MAIO", "JUNHO", "JULHO", "AGOSTO", "SETEMBRO", "OUTUBRO", "NOVEMBRO", "DEZEMBRO"];

      const sortedMonths = [...allMonths].sort((a, b) => {
        const statusA = statusOrder[a.status] || 99;
        const statusB = statusOrder[b.status] || 99;

        if (statusA !== statusB) return statusA - statusB;

        if (a.ano !== b.ano) return b.ano - a.ano;
        return meses_nomes.indexOf(b.nome.toUpperCase()) - meses_nomes.indexOf(a.nome.toUpperCase());
      });

      setMonths(sortedMonths);
    } catch (err) {
      console.error("Erro ao carregar histórico:", err);
    } finally {
      setLoading(false);
    }
  };

  const closeMonthRoutine = async () => {
    if (currentMonth.status !== 'ativo') {
      alert("Apenas o mês ativo pode ser encerrado.");
      return;
    }

    if (!confirm(`Deseja encerrar ${currentMonth.nome}/${currentMonth.ano}? Esta ação migrará automaticamente as parcelas pendentes para o próximo mês.`)) return;

    const [r, d, p, b] = await Promise.all([
      supabaseClient.from('receitas').select('valor').eq('mes_id', currentMonth.id),
      supabaseClient.from('despesas_contas').select('valor').eq('mes_id', currentMonth.id).eq('pago', true),
      supabaseClient.from('despesas_pix_credito').select('valor_final').eq('mes_id', currentMonth.id).eq('pago', true),
      supabaseClient.from('banco_despesas').select('valor').eq('mes_id', currentMonth.id).eq('pago', true)
    ]);

    const rev = r.data?.reduce((a,c) => a + c.valor, 0) || 0;
    const exp = (d.data?.reduce((a,c) => a + c.valor, 0) || 0) + 
                (p.data?.reduce((a,c) => a + c.valor_final, 0) || 0) + 
                (b.data?.reduce((a,c) => a + c.valor, 0) || 0);
    const total = rev - exp;

    // 1. Fecha o mês atual
    await supabaseClient.from('meses').update({ status: 'fechado', saldo_final: total }).eq('id', currentMonth.id);

    // 2. Busca e Ativa o mês de destino
    const meses_nomes = ["JANEIRO", "FEVEREIRO", "MARÇO", "ABRIL", "MAIO", "JUNHO", "JULHO", "AGOSTO", "SETEMBRO", "OUTUBRO", "NOVEMBRO", "DEZEMBRO"];
    let idx = meses_nomes.indexOf(currentMonth.nome.toUpperCase());
    let nextIdx = (idx + 1) % 12;
    let nextYear = idx === 11 ? currentMonth.ano + 1 : currentMonth.ano;
    const nextMonthName = meses_nomes[nextIdx];

    const { data: nextMonths } = await supabaseClient
      .from('meses')
      .select('*')
      .eq('nome', nextMonthName)
      .eq('ano', nextYear);

    const nextMonthData = nextMonths?.[0];

    if (nextMonthData) {
      // Ativa o próximo mês
      await supabaseClient.from('meses').update({ status: 'ativo' }).eq('id', nextMonthData.id);

      // 3. Migração de Parcelamentos (Lógica de continuidade corrigida)
      const { data: installments } = await supabaseClient
        .from('parcelamentos')
        .select('*')
        .eq('mes_id', currentMonth.id);

      if (installments && installments.length > 0) {
        // Filtra parcelas que ainda não foram totalmente quitadas
        const pending = installments.filter(i => (i.parcela_atual || 0) < (i.total_parcelas || 0));

        if (pending.length > 0) {
          const carryOver = pending.map(i => ({
            mes_id: nextMonthData.id,
            descricao: i.descricao,
            valor_parcela: i.valor_parcela,
            parcela_atual: (i.parcela_atual || 0) + 1, // Incrementa a parcela para o novo mês
            total_parcelas: i.total_parcelas
          }));

          const { error: insertError } = await supabaseClient.from('parcelamentos').insert(carryOver);
          if (insertError) console.error("Erro ao migrar parcelas:", insertError.message);
        }
      }
    } else {
      alert(`Atenção: O mês de ${nextMonthName} não foi encontrado. As parcelas não foram migradas.`);
    }

    alert(`Mês de ${currentMonth.nome} encerrado. As parcelas pendentes foram movidas para ${nextMonthName}.`);
    onRefresh();
    fetchMonths();
  };

  const formatCurrency = (val: number) => 
    new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);

  return (
    <div className="space-y-8 animate-in fade-in duration-700 pb-20">
      {currentMonth.status === 'ativo' && (
        <div className="bg-gray-900 p-8 sm:p-12 rounded-[2.5rem] flex flex-col md:flex-row items-center justify-between gap-8 shadow-2xl">
          <div className="flex items-center gap-6 text-white">
            <div className="bg-white/10 p-5 rounded-3xl backdrop-blur-sm border border-white/5">
              <LockKeyhole size={32} />
            </div>
            <div>
              <h3 className="text-2xl font-black uppercase tracking-tighter leading-none mb-2">Encerrar Ciclo</h3>
              <p className="text-white/40 text-xs font-bold uppercase tracking-widest max-w-xs">Fecha o mês e migra parcelas pendentes automaticamente.</p>
            </div>
          </div>
          <button 
            onClick={closeMonthRoutine}
            className="w-full md:w-auto bg-white text-gray-900 px-10 py-5 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-gray-100 transition shadow-xl active:scale-95"
          >
            Fechar Mês Agora
          </button>
        </div>
      )}

      <div className="bg-white rounded-[2.5rem] shadow-sm border border-gray-100 p-8 lg:p-12">
        <h3 className="text-xl font-black mb-10 flex items-center gap-3 text-gray-800">
          <Calendar className="text-gray-400" size={24} />
          ARQUIVO MENSAL
        </h3>

        {loading ? (
          <div className="py-24 flex flex-col items-center gap-4">
            <div className="w-10 h-10 border-4 border-gray-900 border-t-transparent rounded-full animate-spin"></div>
            <p className="text-[10px] font-black uppercase tracking-widest text-gray-400">Varrendo Registros...</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {months.map(m => (
              <div 
                key={m.id} 
                className={`p-6 rounded-[1.8rem] border flex items-center justify-between transition-all group ${
                  m.status === 'ativo' ? 'bg-green-50/20 border-green-100' :
                  m.status === 'provisionamento' ? 'bg-blue-50/20 border-blue-100' :
                  'bg-gray-50/30 border-gray-100 hover:border-gray-200'
                }`}
              >
                <div className="flex items-center gap-5">
                  <div className={`p-4 rounded-2xl shadow-sm ${
                      m.status === 'ativo' ? 'bg-green-600 text-white' :
                      m.status === 'provisionamento' ? 'bg-blue-600 text-white' :
                      'bg-white text-gray-300 border border-gray-100'}`
                  }>
                    {m.status === 'ativo' ? <Unlock size={20} /> :
                     m.status === 'provisionamento' ? <CalendarPlus size={20} /> :
                     <LockKeyhole size={20} />}
                  </div>
                  <div>
                    <h4 className="font-black text-gray-900 text-base uppercase tracking-tight">{m.nome} {m.ano}</h4>
                    <span className={`text-[9px] font-black uppercase tracking-[0.15em] px-2.5 py-1 rounded-lg ${
                        m.status === 'ativo' ? 'bg-green-100 text-green-700' :
                        m.status === 'provisionamento' ? 'bg-blue-100 text-blue-700' :
                        'bg-gray-200 text-gray-500'}`
                    }>
                      {m.status === 'provisionamento' ? 'Planejamento' : m.status}
                    </span>
                  </div>
                </div>

                <div className="text-right">
                  {m.status === 'fechado' ? (
                    <p className="text-base font-black text-gray-900 tracking-tighter">{formatCurrency(m.saldo_final)}</p>
                  ) : (
                    <p className="text-[10px] text-gray-400 font-black uppercase tracking-widest">
                      {m.status === 'ativo' ? 'Ativo' : 'Futuro'}
                    </p>
                  )}
                  <button 
                    onClick={() => onSelectMonth(m)}
                    className="mt-2 text-[10px] font-black uppercase tracking-widest flex items-center gap-1.5 ml-auto text-gray-900 hover:gap-2 transition-all"
                  >
                    ACESSAR <ChevronRight size={14} />
                  </button>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default Closing;

import React, { useState, useEffect } from 'react';
import { CalendarClock, Trash2, X as LucideX, Info, Wallet, Pencil } from 'lucide-react';
import { supabaseClient } from '../services/supabase';
import { Month, Installment } from '../types';

interface InstallmentsProps {
  currentMonth: Month;
  triggerAdd: number;
}

const Installments: React.FC<InstallmentsProps> = ({ currentMonth, triggerAdd }) => {
  const [installments, setInstallments] = useState<Installment[]>([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [editingId, setEditingId] = useState<number | null>(null);
  const [confirmDeleteId, setConfirmDeleteId] = useState<number | null>(null);
  const [formData, setFormData] = useState({ desc: '', val: 'R$ 0,00', atual: '1', total: '1' });

  useEffect(() => {
    fetchData();
  }, [currentMonth]);

  useEffect(() => {
    if (triggerAdd > 0) {
      setEditingId(null);
      setFormData({ desc: '', val: 'R$ 0,00', atual: '1', total: '1' });
      setShowModal(true);
    }
  }, [triggerAdd]);

  const fetchData = async () => {
    setLoading(true);
    try {
      const { data } = await supabaseClient
        .from('parcelamentos')
        .select('*')
        .eq('mes_id', currentMonth.id)
        .order('criado_em', { ascending: false });
      setInstallments(data || []);
    } catch (error) {
      console.error("Erro ao buscar parcelamentos:", error);
    } finally {
      setLoading(false);
    }
  };

  const maskCurrency = (value: string) => {
    const digits = value.replace(/\D/g, "");
    const amount = Number(digits) / 100;
    return new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(amount);
  };

  const parseCurrency = (value: string) => parseFloat(value.replace(/[^\d,]/g, '').replace(',', '.')) || 0;
  const formatCurrency = (val: number) => new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);

  const openEditModal = (item: Installment) => {
    setEditingId(item.id);
    setFormData({
      desc: item.descricao || '',
      val: maskCurrency(((item.valor_parcela || 0) * 100).toString()),
      atual: (item.parcela_atual ?? 1).toString(),
      total: (item.total_parcelas ?? 1).toString()
    });
    setShowModal(true);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const val = parseCurrency(formData.val);
    const payload = {
      mes_id: currentMonth.id,
      descricao: formData.desc,
      valor_parcela: val,
      parcela_atual: parseInt(formData.atual, 10),
      total_parcelas: parseInt(formData.total, 10)
    };

    if (editingId) {
      await supabaseClient.from('parcelamentos').update(payload).eq('id', editingId);
    } else {
      await supabaseClient.from('parcelamentos').insert([payload]);
    }

    setShowModal(false);
    setEditingId(null);
    fetchData();
  };

  const handleDelete = async (id: number) => {
    await supabaseClient.from('parcelamentos').delete().eq('id', id);
    setConfirmDeleteId(null);
    fetchData();
  };

  const canEdit = currentMonth.status !== 'fechado';

  return (
    <div className="space-y-4 animate-in fade-in duration-300">
      {loading ? (
        <div className="py-20 flex flex-col items-center gap-3 text-gray-400">
          <div className="w-8 h-8 border-3 border-green-700 border-t-transparent rounded-full animate-spin"></div>
          <p className="font-bold uppercase tracking-widest text-[9px]">Sincronizando...</p>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
          {installments.length === 0 ? (
            <div className="col-span-full py-20 bg-white rounded-3xl border border-dashed border-gray-200 flex flex-col items-center justify-center text-gray-400">
              <CalendarClock size={32} className="mb-2 opacity-20" />
              <p className="font-bold uppercase tracking-widest text-[10px]">Sem parcelas ativas para {currentMonth.nome}</p>
            </div>
          ) : (
            installments.map(item => {
              const pAtual = item.parcela_atual ?? 1;
              const pTotal = item.total_parcelas ?? 1;
              const pValor = item.valor_parcela ?? 0;
              const parcelasPendentes = Math.max(0, (pTotal - pAtual + 1));
              const totalQuitacao = pValor * parcelasPendentes;

              return (
                <div key={item.id} className="bg-white rounded-3xl p-5 border border-gray-100 shadow-sm flex flex-col">
                  <div className="flex justify-between items-start mb-4">
                    <div className="flex items-center gap-3 min-w-0">
                      <div className="bg-blue-50 p-2 rounded-xl text-blue-600 shrink-0"><CalendarClock size={18} /></div>
                      <div className="min-w-0">
                        <h4 className="font-bold text-gray-800 text-sm truncate">{item.descricao}</h4>
                        <p className="text-[9px] text-gray-400 font-bold uppercase tracking-widest">Progresso: {pAtual}/{pTotal}</p>
                      </div>
                    </div>
                    {canEdit && (
                      <div className="flex items-center">
                        <button onClick={() => openEditModal(item)} className="text-gray-300 hover:text-blue-600 p-1.5"><Pencil size={16} /></button>
                        {confirmDeleteId === item.id ? (
                          <button onClick={() => handleDelete(item.id)} className="text-red-600 font-black text-[9px] uppercase px-2">Sim</button>
                        ) : (
                          <button onClick={() => setConfirmDeleteId(item.id)} className="text-gray-300 hover:text-red-500 p-1.5"><Trash2 size={16} /></button>
                        )}
                      </div>
                    )}
                  </div>

                  <div className="grid grid-cols-2 gap-2 mb-4">
                    <div className="bg-gray-50/50 p-3 rounded-2xl border border-gray-50">
                      <p className="text-[8px] font-black text-gray-400 uppercase tracking-widest mb-0.5">Vl Parcela</p>
                      <p className="text-sm font-black text-gray-800">{formatCurrency(pValor)}</p>
                    </div>
                    <div className="bg-gray-50/50 p-3 rounded-2xl border border-gray-50">
